{
  "name": "Tennessee LIHEAP",
  "eligibility": {
    "age": null,
    "income_limits": "At or below 60% of State Median Income (SMI). Gross monthly income limits for 2025: 1 person $2,671; 2 people $3,492; 3 people $4,314; 4 people $5,136; 5 people $5,958; 6 people $6,780. Some regions reference 150% Federal Poverty Level. Priority for households with member under 6, disabled, over 60, or veterans.[1][2][4][5]",
    "asset_limits": "No asset limit.[1]",
    "other_requirements": ["Household responsible for own energy costs.", "Must live in service area of local agency.", "Priority populations: elderly (60+), disabled, children under 6, veterans.", "Crisis: facing shut-off, out of fuel, or emergency."][2][5][6]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment to utility or fuel provider. Regular heating/cooling: $174-$750 (varies by energy burden); max $1,000 heating/cooling; min $600. Crisis: up to $1,000. Older data: $250 regular/emergency, $325 summer cooling. Once per program year, up to two programs.[1][3][5]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: SmartSimple portal at thda.org (opens Nov 1, 2025, 8AM CST).", "Phone/in-person/mail: Contact local agency (20 agencies statewide; see LIHEAP-Contacts PDF). Examples: ETHRA counties (865-691-2551 etc.), Douglas-Cherokee, Highland Rim (931.289.4101).", "Crisis: Call local office for priority."][2][3][4][5][6],
    "processing_time": "Within 60 days of application month end if funds available.[2]",
    "waitlist": "Possible; eligible placed on list until funds released (e.g., federal delays). Crisis prioritized.[4]",
    "forms": ["2025 LIHEAP Application (local agency form).", "Zero-income form if applicable.", "Self-employment income form."][2][6],
    "documents": ["Government ID.", "SSN for all over age 1.", "Proof of gross income (check stubs last 30 days, SSA statements; not bank statements except SSI/SS).", "12-month utility usage printout.", "Veteran/military proof (DD214, ID).", "Zero-income declaration if no income over 18."][2][6]
  },
  "geography": {
    "statewide": true,
    "restrictions": "All 95 counties via 19-20 local non-profit/government agencies.[3][5]",
    "regional_variations": "Administered by local providers (e.g., ETHRA for Anderson/Campbell/etc., Douglas-Cherokee, Highland Rim). Varying docs, contacts, waitlists, priority scoring (income, energy %, vulnerable members). Applications year-round or seasonal.[2][4][6]",
    "offices_or_providers": ["Network of 20 agencies; contacts at https://s3.amazonaws.com/thda.org/Documents/Business-Partners/Grant-Administrators/LIHEAP-Contacts-2.pdf.[3]"]
  },
  "official_source": "https://thda.org/help-for-homeowners/low-income-home-energy-assistance-program-liheap/[5]",
  "gotchas": ["Funding limited; waitlists common due to federal delays (e.g., no 2026 funds yet).", "Household includes all at address sharing utility.", "One-time per year; priority scoring based on income/energy burden/vulnerable members.", "Crisis needs shut-off notice/out of fuel proof.", "Apps open Nov 1; prepare docs early.", "Benefits to utility/vendor only, not cash.[1][2][4][5]"],
  "data_shape_notes": "Administered via 19-20 local agencies with regional providers, docs, and priority systems; benefits scaled by energy burden, household size, and tier; federal funding delays cause waitlists; statewide but county-agency specific."
}

{
  "name": "Tennessee SHIP",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to anyone with Medicare questions, focused on Medicare-eligible individuals (typically 65+ or disabled) and their families/caregivers[1][3][8][9]",
    "asset_limits": "No asset limits or tests apply[9]",
    "other_requirements": ["Must be Medicare-eligible or have Medicare-related questions; no other restrictions[3][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling on Medicare (Parts A/B, Advantage, Part D, Medigap), enrollment assistance, Medicare Savings Programs (QMB/SLMB/QI), Extra Help/LIS applications, plan comparisons, billing errors/fraud reporting, preventive services education, community outreach/presentations; no financial payments or fixed hours/dollars[1][2][3][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-877-801-0044 (statewide toll-free), local examples 901-222-4111 (Shelby); Email: dda.ship@tn.gov; Online contact form at tn.gov/disability-and-aging; In-person at regional offices; Mail not specified[2][3][7]"],
    "processing_time": "Immediate phone/email assistance; in-person appointments scheduled upon request, no fixed processing time[3]",
    "waitlist": null,
    "forms": ["Contact form on tn.gov site; worksheets for Part D/Medicare Savings (e.g., Part D Worksheet) available via tnmedicarehelp.com[3][5]"],
    "documents": ["No specific documents required for counseling; for assistance programs like Extra Help/MSP, income/asset proofs may be needed during application help[2][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Tennessee[1][3][4]",
    "regional_variations": "Administered via 9 regional SHIPs with local offices/providers (e.g., Aging Commission of Mid-South for Shelby/Fayette/Lauderdale/Tipton; Upper Cumberland for 14-county region); local phone numbers and contacts vary, but services uniform[2][7]",
    "offices_or_providers": ["Tennessee Commission on Aging and Disability (state), 502 Deaderick St., Nashville TN 37243; regional examples: Aging Commission of Mid-South, Upper Cumberland SHIP[2][4][7]"]
  },
  "official_source": "https://www.tn.gov/disability-and-aging/disability-aging-programs/tn-ship.html[3]",
  "gotchas": ["Not a direct financial aid program—provides counseling only, not payments; does not sell/endorses insurance; must disenroll from ACA Marketplace upon Medicare eligibility to avoid penalties; focused on Medicare, not general healthcare[3][5]; regional offices handle local service but statewide consistency[2]"],
  "data_shape_notes": "No income/asset/age tests; counseling-only service via regional network; open access for Medicare beneficiaries/families statewide"
}

{
  "name": "Tennessee Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or asset limits apply; income is not a factor in determining eligibility, though programs target low-income seniors and may suggest contributions on a sliding scale based on ability to pay[1][6][8]",
    "asset_limits": "No asset limits; no information on what counts or exemptions as assets are not tested[1][6]",
    "other_requirements": ["Homebound due to illness, incapacitation, disability, or mobility challenges that make shopping, preparing meals, or socializing difficult[1][2][3][4][8]", "Reside in the service area or delivery zone of the local provider (varies by region)[1][2]", "Unable to obtain nutritious meals from family, friends, or other resources[2]", "For some programs, spouses or dependents of eligible 60+ individuals may qualify regardless of age; disabled under 60 in specific settings like senior high-rises[2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritionally balanced noontime meal providing one-third of daily RDA requirements (typically weekdays); includes friendly volunteer visit and safety check; congregate meals available at senior centers/community sites for socialization and nutrition education[1][2][4][7][8][9]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-866-836-6678 to contact local Area Agency on Aging and Disability (AAAD)[7][8][9]", "Online: Use screening tool at local AAAD sites (e.g., NWTDD) or find provider via Meals on Wheels America locator[3][9]", "In-person: At local AAAD offices, senior centers, or congregate meal sites[8]", "Referral: Doctor, social worker, or family can refer[3]"],
    "processing_time": "Varies; some process within a week, others longer if waitlisted; intake assessment by case manager required[1]",
    "waitlist": "Possible in some programs/regions due to high demand[1]",
    "forms": ["Application and needs assessment via local AAAD; no specific statewide form name/number identified[1][3][8]"],
    "documents": ["Proof of age, residence, medical information (e.g., dietary restrictions, conditions); financial documents sometimes requested but not required for eligibility; doctor/social worker referral letter may be needed[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must live in the delivery/service area of local provider; available in all 95 Tennessee counties via local AAADs[2][8]",
    "regional_variations": "Administered by local Area Agencies on Aging and Disability (AAAD) with over 150 congregate sites; specific eligibility nuances, delivery zones, and wait times vary by agency (e.g., Davidson County requires county residency; Mid-Cumberland serves Middle TN; SETAAAD for Southeast TN)[2][4][7][8]",
    "offices_or_providers": ["Local AAADs (e.g., Mid-Cumberland HRA, SETAAAD, NWTDD, DCEA); contact 1-866-836-6678 for your area[4][7][8][9]"]
  },
  "official_source": "https://www.tn.gov/disability-and-aging/disability-aging-programs/aging-nutrition-program.html",
  "gotchas": ["Not a single centralized program—must contact local AAAD for your county as rules/zones vary; car ownership or ability to leave home easily may disqualify; some programs funded via Title III (no cost, donations suggested) vs. Medicaid CHOICES (separate qualification); congregate vs. home-delivered have different criteria; outside service areas requires alternatives[1][2][5][8]"],
  "data_shape_notes": "Decentralized by  local AAAD per county/region with no statewide income/asset test; homebound requirement strictly assessed; over 150 congregate sites but home delivery zone-restricted"
}

{
  "name": "Tennessee Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Varies by program; some like Legal Aid of East Tennessee require income under 125% of Federal Poverty Guidelines (exact dollar amounts not specified in sources and vary by household size/year); others like Free Senior Legal Helpline have no income limits[1][7][8].",
    "asset_limits": "No asset limits mentioned for senior-specific programs; Free Senior Legal Helpline explicitly states no asset test[7].",
    "other_requirements": ["Must personally contact program office (waivable in emergencies)[1]", "Civil legal issues only (e.g., not criminal cases)[1][4]", "Priority for emergencies threatening harm or death[1]", "Specific case types set by state priority categories[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free confidential legal advice, representation, and referrals on civil matters including landlord/tenant, probate, healthcare access (TennCare/Medicare), domestic violence family issues, Medicaid eligibility, guardianship/conservatorship; no charge for attorney time (may have court costs); remote delivery available[1][4][7].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Free Senior Legal Helpline 844-435-7486 (statewide)[7]", "Phone: ETHRA Legal Assistance for Elderly (865) 691-2551 ext 4212 or ext 4216 (East TN)[1]", "Website: https://www.ethra.org/programs/21/legal-assistance-for-the-elderly (East TN)[1]", "Website: https://www.tals.org/page/453/free-senior-legal-helpline[7]", "Website: https://www.laet.org (Legal Aid East TN)[10]", "In-person: ETHRA Knoxville office 1514 E. Fifth Avenue, Knoxville, TN 37917; Legal Aid offices vary by region[1]", "Online legal advice: https://tn.freelegalanswers.org/ (statewide for qualifying seniors)[5]"],
    "processing_time": "Emergencies given priority; others first-come first-served as capacity allows; no specific timelines stated[1].",
    "waitlist": "Yes, when caseload maxed; option for waiting list or referral to others[1].",
    "forms": ["No specific form names/numbers listed; intake via phone or online questions[1][5][7]"],
    "documents": ["Income proof for income-based programs; details on legal problem; no full list specified[2][4]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Regional providers cover specific areas (e.g., ETHRA East TN: Blount, Claiborne, etc. counties; Legal Aid offices by region)[1]",
    "regional_variations": "Different providers by region (East TN: ETHRA/LAET; Middle TN: varies; Upper Cumberland noted); wait times vary by caseload capacity; 8 Legal Aid orgs total[1][4][5].",
    "offices_or_providers": ["ETHRA (East TN)[1]", "Legal Aid of East Tennessee[10]", "Tennessee Alliance for Legal Services (helpline statewide)[7]", "Regional Legal Aid offices (8 total)[4]"]
  },
  "official_source": "https://www.tals.org/page/453/free-senior-legal-helpline (statewide helpline); https://www.ethra.org/programs/21/legal-assistance-for-the-elderly (East TN example)",
  "gotchas": ["Not all civil cases covered (e.g., no criminal, no fee-generating like car accidents)[1][4]", "May need to pay court costs despite free legal help[4]", "Personal contact required (waivable only in emergencies)[1]", "Limited capacity leads to waitlists/referrals[1]", "Income screening even if not always disqualifying[2][4][8]"],
  "data_shape_notes": "Regionally administered via multiple providers (not single statewide program); priority tiers by case type/emergency; some no income test but most Legal Aid have poverty guideline limits; varies heavily by East/Middle/West TN"
}

{
  "name": "OPTIONS for Community Living",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict upper income limit; if income exceeds Federal Poverty Guidelines, a cost share is required. Medicaid-related programs like CHOICES have separate limits (e.g., $2,982/month for 2026, or 3x SSI Federal Benefit Rate).[3][4]",
    "asset_limits": "No asset limits mentioned for OPTIONS; Medicaid-linked programs like CHOICES limit countable assets to $2,000 (home exempt if equity ≤$730,000 in 2025, or if spouse/child lives there).[1][3]",
    "other_requirements": [
      "Tennessee resident.",
      "Require assistance with at least 3 Activities of Daily Living (ADLs) or Instrumental ADLs (IADLs), such as mobility, toileting, hygiene, dressing, housekeeping, cooking, shopping, bathing; certified by medical professional.",
      "For ages 18-60, must be disabled per Social Security determination.[2][4]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Light housekeeping, assistance with bathing, home-delivered meals, case management.[4]",
    "varies_by": "income (cost share if over FPL); physical need and availability (prioritization on waitlist); region (via local Area Agencies on Aging).[2][4]"
  },
  "application": {
    "methods": [
      "Phone: Call FTAAAD Information and Assistance line at 1-866-836-6678 for screening and application.[2][4]",
      "In-person or mail: Contact local Area Agency on Aging and Disability (e.g., ETHRA for specific counties); download intake form from agency website.[4]"
    ],
    "processing_time": "Intake screening by phone; if eligible and slot available, in-home assessment by case manager (timeline not specified).[4]",
    "waitlist": "Waiting lists have existed in past years; prioritization based on income and physical need. Slots must be available.[2][4]",
    "forms": ["Intake Form (download from local agency website, e.g., ETHRA).[4]"],
    "documents": ["Medical certification of ADL/IADL needs; income details for cost share determination; have intake form details ready (health, income, support info).[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through regional Area Agencies on Aging and Disability (e.g., ETHRA serves Blount, Claiborne, Campbell, Anderson, Knox, Morgan, Cocke, Grainger, Hamblen, Jefferson, Loudon, Monroe, Roane, Scott, Sevier, Union Counties).[4]",
    "regional_variations": "Delivered by local Area Agencies; potential differences in providers, wait times, and availability by region.[2][4]",
    "offices_or_providers": ["FTAAAD (statewide intake: 1-866-836-6678); local agencies like ETHRA.[2][4]"]
  },
  "official_source": "https://www.ftaaad.org/options-subpage[2]",
  "gotchas": [
    "Waiting lists common; eligibility doesn't guarantee immediate services—prioritized by income/need.[2]",
    "Cost share if income over FPL—often missed.[4]",
    "Must have at least 3 ADL/IADL deficits; re-screen if previously denied due to health changes.[2][4]",
    "Separate from TennCare CHOICES (which requires NFLOC and has stricter financial rules)—don't confuse.[1][3]"
  ],
  "data_shape_notes": "State-funded via Tennessee Commission on Aging and Disability; no strict income/asset caps but cost share applies; regional delivery through Area Agencies with waitlists and prioritization; functional need (3+ ADLs) drives eligibility, not Medicaid linkage."
}
